var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>북쪽 거주 구획에서 상황 발생! 군은 언제 오는 거야?!</color>","JPN":"<color=#ffd34c>北の居住区域から状況発生！　軍はいつ来るんだ！？</color>","ENG":"<color=#ffd34c>Something horrible is happening in the northern side of the city! When will the army arrive?!</color>","TWN":"<color=#ffd34c>北邊的住宅區有狀況發生！軍隊什麼時候抵達？！</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이봐! 아무나 제발 대답 좀 해! 건물이 치즈처럼 뭉개지고 있다고!</color>","JPN":"<color=#ffd34c>おい！　誰でもいいから返事しろ！　建物がチーズのようにぶっ潰されてんだぞ！</color>","ENG":"<color=#ffd34c>Hey! Is anybody out there? The buildings are melting like cheese!</color>","TWN":"<color=#ffd34c>喂！有人可以回答我嗎！建築物都塌啦！</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>침식체 핑계로 언제까지 못 본 척 할 거야! 이러다 다 죽게 생겼단 말이다!</color>","JPN":"<color=#ffd34c>侵食体を言い訳にいつまで見ぬふりしてやがるつもりだ！　これでは全員死ぬぞ！</color>","ENG":"<color=#ffd34c>How long are you going to ignore this using the excuse of a Corrupted Object appearing! We’re all going to die!</color>","TWN":"<color=#ffd34c>你們要拿侵蝕體當藉口，視而不見到什麼時候！再這樣下去我們全都會死的！</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"지금 들으신 내용은 현재 타나베린의 교신 중 일부입니다.","JPN":"今の内容は現在のタナベリンの交信の一部です。","ENG":"What you heard was just part of the communication occurring in Tanaberin right now.","TWN":"現在聽到的內容，是達那貝林通訊中的一部分。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"관리국 정찰 위성의 영상을 분석했을 때 완파된 건물만 수십 채로 파악됩니다.","JPN":"管理局の偵察衛星の映像を分析してみた結果、全壊した建物は数十軒に及びます。","ENG":"Analysis of images from the Administration’s surveillance satellite confirms dozens of destroyed buildings.","TWN":"分析管理局偵查衛星的影像後發現，光是全毀的建築物就有數十棟。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"……부전대장님 말씀대로군요. 서둘러 돌아오길 잘했습니다.","JPN":"……副戦隊長の言うとおりですね。急いで帰ってきて正解でした。","ENG":"...It’s as the Deputy Commander warned us. It’s good we got here fast.","TWN":"……果然跟副戰隊長說的一樣，幸好我們及早調頭。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"글쎄. 문제는 누가 저런 짓을 벌였는지야. 역시 엘리시움 필하모닉이려나.","JPN":"さあ。問題は誰があんなことをやらかしたのかなの。やっぱりエリシウムフィルハーモニーかな。","ENG":"Well. Now the question is who is behind all this. The Elysium Philharmonic?","TWN":"是嗎？問題是犯人是誰？是愛樂組織幹的嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"네. 정찰 위성에 포착된 개체의 형태는 다음과 같습니다.","JPN":"はい。偵察衛星で捉えられた個体の形はこちらです。","ENG":"The surveillance satellite picked up the following individuals.","TWN":"根據偵查衛星捕捉到的形象如下。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"저건…… 설마 모르스인가?","JPN":"あれは……もしかしてモールス？","ENG":"That’s... No way, Mors?","TWN":"那個……該不會是莫爾斯？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"모르스라면 <color=#ffd34c>성야의 살인마</color> 아닙니까?","JPN":"モールスなら、<color=#ffd34c>聖夜の殺人鬼</color>ではありませんか？","ENG":"Mors... You mean <color=#ffd34c>The Killer of the Holy Night</color>?","TWN":"莫爾斯不就是<color=#ffd34c>聖夜的嫌疑犯</color>嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 들은 적 있어. 놀이의 원형이 저 그림자라는 얘기는.","JPN":"そう。聞いたことがある。遊びの原型があのシャドウだって話ね。","ENG":"Ahh, right. I’ve heard that the game originates from that Shadow.","TWN":"對，聽說遊戲的原型就是那個暗影。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"칩거하다가 갑자기 나타나서는, 한바탕 휩쓸고 사라지는 그림자……. 였지.","JPN":"籠ってはいきなり出てきて、ひとしきり暴れてはまた消えるシャドウ……だっけ。","ENG":"A Shadow that lives in recluse, sometimes appearing and wreaking havoc, only to mysteriously disappear again.","TWN":"蟄伏一陣子後，突然冒出來大鬧一場，接著又消失不見的……暗影。"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"저 갑옷이 침식파를 차단하는 바람에 예전 관리국도 몇 번 골탕 먹었다고 했어.","JPN":"あの鎧が侵食波を遮断するせいで、昔の管理局も何回かやられたらしいわ。","ENG":"I heard she put the Old Administration through trouble as her armor blocked Corruption rays.","TWN":"她身上的鎧甲可以隔離侵蝕波，聽說管理局以前也因此吃過幾次苦頭。"},"stage":{"bg":"COUNTERSIDE_GREEN","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그렇다면…… 표식으로 상대를 조종하는 힘이 있을지도 모르겠군요.","JPN":"それでしたら……印を付けて相手を操る力があるのかも知れませんね。","ENG":"If that’s the case... She might have the power to manipulate her opponent with her mark.","TWN":"這樣的話……或許可以用標誌來控制對方？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그건 놀이에 맞게 꾸민 얘기지. 도끼날로 머리를 찍는다는 설정은 과격하잖아.","JPN":"それは遊びに合わせて作り上げた話よ。斧で頭を割るなんて設定は過激すぎるじゃない。","ENG":"That’s just a story made up for the game. It was a bit too extreme to have it be chopping someone’s head off with an axe.","TWN":"那只是配合遊戲設定而捏造的，不覺得用斧頭砍掉頭的設定很誇張嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"으음……. 듣고 보니 확실히…….","JPN":"ううむ……そういえば確かに……","ENG":"Hmm... That all makes sense...","TWN":"嗯……聽你這麼說確實是……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};